<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">SECURITY</span><h1>Roles and Permissions</h1><p>Administrators always retain full access.</p></div></div><form class="admin-panel admin-search" method="post" action="<?=url('admin/role-create')?>"><?=csrf_field()?><input name="name" placeholder="Role key, e.g. receptionist" required><input name="label" placeholder="Display label" required><button class="btn">Create Role</button></form><div class="role-grid"><?php foreach($roles as$r):?><form class="admin-panel role-card" method="post" action="<?=url('admin/roles')?>"><?=csrf_field()?><input type="hidden" name="role_id" value="<?=$r['id']?>"><h2><?=e($r['label'])?></h2><small><?=e($r['name'])?></small><div class="permission-list"><?php foreach($permissions as$p):?><label><input type="checkbox" name="permissions[]" value="<?=$p['id']?>" <?=in_array((int)$p['id'],$r['permission_ids'],true)?'checked':''?> <?=$r['name']==='admin'?'disabled':''?>><span><b><?=e($p['label'])?></b><small><?=e($p['name'])?></small></span></label><?php endforeach;?></div><?php if($r['name']!=='admin'):?><button class="btn">Save Permissions</button><?php else:?><p class="disclaimer">The main administrator role cannot be restricted from this interface.</p><?php endif;?></form><?php endforeach;?></div></div></section>
